INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('immigration-1aab856d-moex-00050', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '檢察官偵查某詐欺案，發現住在臺南市的甲犯罪嫌疑重大，且有事證指出可能逃亡海外，乃對甲 發動限制出境、出海。下列敘述何者正確？', '["應有令狀，且應立刻通知並訊問甲", "毋庸令狀，但應立刻通知並訊問甲", "應有令狀，但限制後6個月內通知甲即可", "毋庸令狀，且限制後6個月內通知甲即可"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "ee1e44310058", "answer_pdf_sha1": "c5d93990a36e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0609", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00051', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '關於偵查中被害人受警察詢問時之敘述，下列何者正確？', '["縱然被害人不同意，被害人的配偶仍得陪同在場，並得陳述意見", "縱然被害人不同意，被害人的法定代理人仍得陪同在場，並得陳述意見", "若被害人同意，其信賴的輔導人員得陪同在場，縱然警察認為有礙警詢進行，仍不得禁止", "若被害人同意，其信賴的公司長官得陪同在場，縱然彼此無任何血緣關係，仍得陪同在場"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "ee1e44310058", "answer_pdf_sha1": "c5d93990a36e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0609", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00052', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '警察通知被告到案說明案情，後函送檢察官進行偵查，再經檢察官起訴，被告於警詢時所為之陳 述是否得作為證據使用？', '["不可以，警詢筆錄為審判外之陳述，應排除證據能力", "不可以，偵訊筆錄有取代警詢筆錄的效果，此時警詢筆錄失去法律上之意義", "可以，若無其他法定排除其證據能力之事由，被告的警詢筆錄不當然沒有證據能力", "可以，案重初供，警詢筆錄證明力極高，不應排除其證據能力"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "ee1e44310058", "answer_pdf_sha1": "c5d93990a36e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0609", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00053', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '告訴人提出告訴後，檢察官以犯罪嫌疑不足為不起訴處分，告訴人聲請再議經上級檢察署檢察長 以再議無理由而以處分書駁回，此時告訴人得如何救濟？', '["聲請第二次再議", "聲請交付審判", "聲請再審", "聲請准許提起自訴"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "ee1e44310058", "answer_pdf_sha1": "c5d93990a36e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0609", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00054', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-ba02692f', 'sub-immigration-1aab856d-02', NULL, 'single_choice', '法院於準備程序時得知關鍵證人即將出國進修，無法於審判期日出庭作證，依照實務見解，此時 應如何處理最為妥適？', '["只能捨棄該證人證詞，此為直接審理原則之必然", "依法傳喚，屆時若不出庭，拘提之", "可以於準備程序訊問證人，但應從嚴適用", "證人毋需出庭，法院直接改用偵查筆錄作為證據"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "ee1e44310058", "answer_pdf_sha1": "c5d93990a36e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0609", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國境執法與刑事法(包括刑法與刑事訴訟法)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00055', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-13504c0c', 'sub-immigration-1aab856d-03', NULL, 'single_choice', '下列文句「」中用詞，何者最為妥切？', '["好友已值「從心所欲」之年，是拚搏事業的好時機", "土耳其大地震，死傷人數慘重，令人「忍俊不住」", "王生誤解了李生的好意，慚愧的登門「負荊請罪」", "他們兄弟感情深厚，真是「舉案齊眉」，令人稱羨"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "8e2479f19be0", "answer_pdf_sha1": "59c0340c3c3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00056', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-13504c0c', 'sub-immigration-1aab856d-03', NULL, 'single_choice', '「樹上的花是小說，有枝有幹地攀在縱橫交叉的結構上，那裡面有多層次、多角度 的說不盡的故事。草花是詩，由於矮，像是剛從土裡蹦上來的，一種精粹的、鮮艷 的、凝聚的、集中的美。散文是爬籐花，都有一種走到那裡就開到那裡的渾灑。如 果有什麼花可以稱之為舞台劇的，大概就是曇花了吧。它是一種徹底的時間藝術， 在絲帷的開闔間即生而即死。」 根據上文，下列選項，何者最接近文意？', '["小說是高高在上，像樹上的花必須仰望", "詩則俯拾即是，就像草花一樣隨處可見", "散文必須像爬籐，要旅行才能寫得渾灑", "舞台劇如曇花，在開幕謝幕間展演人生"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "8e2479f19be0", "answer_pdf_sha1": "59c0340c3c3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00057', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-13504c0c', 'sub-immigration-1aab856d-03', NULL, 'single_choice', '「最有名的顯性遺傳疾病，莫過於杭丁頓舞蹈症（Huntington''s Disease）。這是一 種異常殘酷的疾病，患者通常要到四、五十歲才會發病。發病後，病人的中樞神經 系統會慢慢退化、肌肉無力、四肢協調性變差，慢慢喪失記憶，性情和行為發生改 變、喪失高層認知功能、癱瘓、進入植物人狀態，最後昏迷、死亡。上述的退化過 程極為緩慢，大約要五到十年，目前沒有任何藥物或任何療法可以減緩病程發展。 病人和摯愛的家人完全無能為力，只能眼睜睜看著這一切發生。」 關於杭丁頓舞蹈症的敘述，下列何者正確？', '["是隱性遺傳疾病，沒有藥物能治療或預防", "發病後會緩慢漸進式退化，病人較能因應", "屬於腦神經系統退化的疾病，發病後即將失去記憶", "病患的家屬，只能眼睜睜看著病人退化而無力挽救"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "8e2479f19be0", "answer_pdf_sha1": "59c0340c3c3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00058', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-13504c0c', 'sub-immigration-1aab856d-03', NULL, 'single_choice', '下列文句，存在語病的是：', '["儘管比賽前他受了點傷，但比賽時依舊所向披靡", "參加試鏡者很少，我得用盡心力才能爭取到角色", "這些八卦新聞經過查證後，實屬空穴來風", "他被債務逼得走投無路，不得不鋌而走險"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "8e2479f19be0", "answer_pdf_sha1": "59c0340c3c3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00059', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-13504c0c', 'sub-immigration-1aab856d-03', NULL, 'single_choice', '「一座臨水的扇面小亭，每當夜深人靜，清風徐來，明月當空，水天上下相映，好 一派清淨幽寂，小亭以蘇軾詞中『與誰同坐，明月清風我』句，取名為『與誰同坐 軒』。」 根據上文，此亭取名「與誰同坐軒」的原因為何？', '["此亭清幽能讓人興起飄飄欲仙之感", "明月與清風正好是臨水小亭的特色", "感念蘇軾的儒雅風采渴望與其同坐", "美景當前總讓人傷嘆無知己可共賞"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "8e2479f19be0", "answer_pdf_sha1": "59c0340c3c3a", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL)
